{"content": "import { services, caseStudies, approach, site, about } from './data'

interface WebMCPTool {
  name: string
  description: string
  inputSchema: Record<string, unknown>
  execute: (params: Record<string, unknown>) => Promise<unknown>
}

/**
 * Registers site tools via the WebMCP API (Chrome experimental).
 * See: https://webmachinelearning.github.io/webmcp/
 */
export function registerWebMCP() {
  const nav = navigator as Navigator & {
    modelContext?: {
      provideContext: (ctx: { tools: WebMCPTool[] }) => Promise<void>
    }
  }

  if (!nav.modelContext) {
    console.log('[Trublue] WebMCP not available in this browser.')
    return
  }

  const tools: WebMCPTool[] = [
    {
      name: 'get_services',
      description:
        'List all operations consulting services offered by Trublue Solution, including descriptions and deliverables for each.',
      inputSchema: {
        type: 'object',
        properties: {},
        required: [],
      },
      execute: async () => ({
        provider: site.legalName,
        services: services.map((s) => ({
          name: s.title,
          description: s.description,
          deliverables: s.deliverables,
        })),
      }),
    },
    {
      name: 'get_case_studies',
      description:
        'List verified case studies with metrics from Trublue Solution engagements: freight brokerage buildout, restaurant turnaround, and legal operations.',
      inputSchema: {
        type: 'object',
        properties: {},
        required: [],
      },
      execute: async () => ({
        provider: site.legalName,
        caseStudies: caseStudies.map((cs) => ({
          domain: cs.domain,
          headline: cs.headline,
          tagline: cs.tagline,
          challenge: cs.challenge,
          results: cs.results,
